      let currentLang = 'en'; 
let currentFilterType = 'all'; 

function toggleMobileMenu() {
    document.getElementById('mobile-menu').classList.toggle('hidden');
}

function checkURLParams() {
    const urlParams = new URLSearchParams(window.location.search);
    const filterType = urlParams.get('type');
    const bookSlug = urlParams.get('book'); // NEW: bookId ki jagah book
    const searchKeyword = urlParams.get('search'); 

    if (bookSlug) {
        initPage(); 
        showBookDetail(bookSlug); // NEW: parseInt hata diya
    } else if (searchKeyword) {
        initPage();
        const searchInput = document.getElementById('realtime-search');
        if(searchInput) {
            searchInput.value = searchKeyword;
            filterBooksBySearch(searchKeyword);
        }
    } else if (filterType && ['genre', 'author', 'title'].includes(filterType)) {
        setFilterType(filterType);
    } else {
        initPage();
    }
}

function initPage() {
    renderBookList(booksData);
    setupDropdownOptions();
}

function renderBookList(data) {
    const listContainer = document.getElementById('book-list-view');
    listContainer.innerHTML = '';

    if(data.length === 0) {
        listContainer.innerHTML = `<div class="col-span-full text-center py-12 text-slate-400">No books found matching your search.</div>`;
        return;
    }

    data.forEach(book => {
        const localized = book[currentLang] || book['en']; 
        
        const card = document.createElement('div');
        card.className = "bg-white p-6 rounded-2xl shadow-sm border border-slate-100 hover:shadow-md transition-all cursor-pointer flex flex-col justify-between group";
        
        // NEW: book.id ki jagah book.slug
        card.onclick = () => showBookDetail(book.slug); 

        card.innerHTML = `
            <div>
                <div class="w-full aspect-[4/5] bg-slate-50 rounded-xl mb-4 overflow-hidden border border-slate-100 shadow-sm relative">
                    <img src="${book.image}" alt="${localized.title}" class="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500">
                </div>
                <span class="text-[11px] font-bold uppercase tracking-wider text-emerald-600 bg-emerald-50 px-2 py-1 rounded-md">${localized.genre}</span>
                <h3 class="text-xl font-serif font-bold text-slate-900 mt-2 group-hover:text-emerald-600 transition-colors">${localized.title}</h3>
                <p class="text-sm text-slate-500 mt-1">By ${localized.author}</p>
            </div>
            <div class="mt-4 pt-4 border-t border-slate-50 flex items-center text-xs font-bold text-slate-700 group-hover:text-emerald-600">
                ${currentLang === 'en' ? 'Read Full Summary' : 'पूरी समरी पढ़ें'} <i class="fa-solid fa-arrow-right ml-2 text-[10px]"></i>
            </div>
        `;
        listContainer.appendChild(card);
    });
}

function setFilterType(type) {
    currentFilterType = type;
    const tabs = ['all', 'genre', 'author', 'title'];
    tabs.forEach(t => {
        const el = document.getElementById(`tab-${t}`);
        if(el) {
            if(t === type) el.className = "px-4 py-2 rounded-lg text-sm font-medium transition-all bg-white text-slate-900 shadow-sm";
            else el.className = "px-4 py-2 rounded-lg text-sm font-medium transition-all text-slate-600 hover:text-slate-900";
        }
    });

    const dropdownContainer = document.getElementById('dynamic-select-container');
    if(type === 'all') {
        if(dropdownContainer) dropdownContainer.classList.add('hidden');
        showListView();
        renderBookList(booksData);
        const searchInput = document.getElementById('realtime-search');
        if(searchInput) searchInput.value = '';
    } else {
        if(dropdownContainer) dropdownContainer.classList.remove('hidden');
        setupDropdownOptions();
    }
    
    const mobileMenu = document.getElementById('mobile-menu');
    if(mobileMenu) mobileMenu.classList.add('hidden');
}

function setupDropdownOptions() {
    const selectEl = document.getElementById('dynamic-select');
    if(!selectEl) return;
    
    selectEl.innerHTML = '';
    let options = [];
    if(currentFilterType === 'genre') {
        options = [...new Set(booksData.map(b => b[currentLang].genre))];
        selectEl.innerHTML = `<option value="">-- Select Genre --</option>`;
    } else if(currentFilterType === 'author') {
        options = [...new Set(booksData.map(b => b[currentLang].author))];
        selectEl.innerHTML = `<option value="">-- Select Author --</option>`;
    } else if(currentFilterType === 'title') {
        options = booksData.map(b => b[currentLang].title);
        selectEl.innerHTML = `<option value="">-- Select Book Title --</option>`;
    }
    options.forEach(opt => selectEl.innerHTML += `<option value="${opt}">${opt}</option>`);
}

function applyDropdownFilter(val) {
    if(!val) { renderBookList(booksData); return; }
    showListView();
    const filtered = booksData.filter(book => book[currentLang][currentFilterType] === val);
    renderBookList(filtered);
}

function toggleLanguage() {
    currentLang = currentLang === 'en' ? 'hi' : 'en';
    document.getElementById('lang-btn-text').innerText = currentLang === 'en' ? 'Switch to Hindi' : 'English में बदलें';
    setupDropdownOptions();
    
    if(document.getElementById('book-list-view').classList.contains('hidden')) {
        const activeSlug = document.getElementById('book-detail-view').dataset.activeBookSlug; // NEW
        if(activeSlug) showBookDetail(activeSlug); // NEW
    } else {
        const searchInput = document.getElementById('realtime-search');
        if(searchInput && searchInput.value.trim() !== '') {
            filterBooksBySearch(searchInput.value);
        } else {
            renderBookList(booksData);
            setFilterType('all');
        }
    }
}

// NEW: id ki jagah slug argument pass hoga
function showBookDetail(slug) {
    const book = booksData.find(b => b.slug === slug); // NEW: find by slug
    if(!book) return;

    const localized = book[currentLang];
    document.getElementById('book-detail-view').dataset.activeBookSlug = slug; // NEW
    
    document.getElementById('detail-img').src = book.image;
    document.getElementById('detail-genre').innerText = localized.genre;
    document.getElementById('detail-title').innerText = localized.title;
    document.getElementById('detail-author').innerText = "By " + localized.author;
    document.getElementById('detail-summary-text').innerText = localized.summary;
    document.getElementById('amazon-link').href = book.links.amazon;
    document.getElementById('flipkart-link').href = book.links.flipkart;
   // NEW CODE: WhatsApp Share Link Generator
// ==========================================
const shareUrl = window.location.origin + window.location.pathname + '?book=' + slug;
const shareMessage = `Check out this 5-minute summary of "${localized.title}": ${shareUrl}`;
document.getElementById('whatsapp-share-btn').href = `https://api.whatsapp.com/send?text=${encodeURIComponent(shareMessage)}`;
// ==========================================

    const pointsContainer = document.getElementById('detail-key-points');
    pointsContainer.innerHTML = '';
    localized.points.forEach((point, index) => {
        pointsContainer.innerHTML += `
            <li class="flex items-start gap-3 text-slate-600 leading-relaxed text-sm md:text-base">
                <span class="flex-shrink-0 bg-emerald-50 text-emerald-600 font-bold w-6 h-6 rounded-full flex items-center justify-center text-xs mt-0.5">${index + 1}</span>
                <span>${point}</span>
            </li>`;
    });

    document.getElementById('book-list-view').classList.add('hidden');
    document.getElementById('book-detail-view').classList.remove('hidden');
    window.scrollTo({ top: 0, behavior: 'smooth' });

    // NEW: URL mein ?bookId ki jagah ?book=slug
    const newUrl = window.location.pathname + '?book=' + slug;
    window.history.pushState({ path: newUrl }, '', newUrl);

    document.title = localized.title + " | 5 Mins Summary";

    let metaDesc = document.querySelector('meta[name="description"]');
    if(metaDesc) {
        metaDesc.setAttribute("content", localized.summary.substring(0, 150) + "...");
    }
}

function showListView() {
    document.getElementById('book-detail-view').classList.add('hidden');
    document.getElementById('book-list-view').classList.remove('hidden');

    const newUrl = window.location.pathname;
    window.history.pushState({ path: newUrl }, '', newUrl);
    document.title = "5 Mins Summary | Knowledge Simplified";
}

function filterBooksBySearch(searchTerm) {
    const term = searchTerm.toLowerCase().trim();
    
    if(term === '') {
        renderBookList(booksData);
        return;
    }

    const filtered = booksData.filter(book => {
        const enTitle = (book.en?.title || '').toLowerCase();
        const enAuthor = (book.en?.author || '').toLowerCase();
        const hiTitle = (book.hi?.title || '').toLowerCase();
        const hiAuthor = (book.hi?.author || '').toLowerCase();

        return enTitle.includes(term) || 
               enAuthor.includes(term) || 
               hiTitle.includes(term) || 
               hiAuthor.includes(term);
    });

    renderBookList(filtered);
}

document.addEventListener('DOMContentLoaded', () => {
    const searchInput = document.getElementById('realtime-search');
    
    if(searchInput) {
        searchInput.addEventListener('input', (e) => {
            showListView(); 
            filterBooksBySearch(e.target.value);
        });
    }
});

window.onload = checkURLParams;

function showLatestSummaries() {
    // Aapki ID descending me sort ho rahi hai (bade numbers pehle), yeh bilkul theek chalega!
    const latestBooks = [...booksData].sort((a, b) => b.id - a.id);
    
    showListView();
    renderBookList(latestBooks);

    const tabs = ['all', 'genre', 'author', 'title'];
    tabs.forEach(t => {
        const el = document.getElementById(`tab-${t}`);
        if(el) {
            el.className = "px-4 py-2 rounded-lg text-sm font-medium transition-all text-slate-600 hover:text-slate-900";
        }
    });
    
    const dropdownContainer = document.getElementById('dynamic-select-container');
    if(dropdownContainer) dropdownContainer.classList.add('hidden');
    
    const searchInput = document.getElementById('realtime-search');
    if(searchInput) searchInput.value = '';
}

window.addEventListener('popstate', () => {
    const urlParams = new URLSearchParams(window.location.search);
    const bookSlug = urlParams.get('book'); // NEW: Update book param
    
    if (bookSlug) {
        showBookDetail(bookSlug); // NEW: parseInt hata diya
    } else {
        showListView();
    }
});
